const body = $input.first().json.body;

// Grafana Unified Alerting Format
const alerts = body.alerts || [];
const status = body.status || 'unknown';
const title = body.title || 'Grafana Alert';
const message = body.message || '';

let color = status === 'firing' ? 'FF0000' : '00AA00';
let icon = status === 'firing' ? '🔴' : '✅';

const alertDetails = alerts.map(a => {
  const labels = Object.entries(a.labels || {}).map(([k, v]) => `${k}=${v}`).join(', ');
  const val = a.values ? Object.entries(a.values).map(([k, v]) => `${k}: ${v}`).join(', ') : '';
  return `**${a.labels?.alertname || 'Alert'}** (${a.status})\n${labels}${val ? '\n' + val : ''}`;
}).join('\n\n');

return [{
  json: {
    type: 'message',
    attachments: [{
      contentType: 'application/vnd.microsoft.card.adaptive',
      content: {
        '$schema': 'http://adaptivecards.io/schemas/adaptive-card.json',
        type: 'AdaptiveCard',
        version: '1.4',
        body: [
          {
            type: 'TextBlock',
            text: `${icon} ${title}`,
            weight: 'Bolder',
            size: 'Medium',
            color: status === 'firing' ? 'Attention' : 'Good'
          },
          {
            type: 'TextBlock',
            text: message || alertDetails || 'Keine Details verfügbar.',
            wrap: true
          },
          {
            type: 'TextBlock',
            text: `Status: **${status.toUpperCase()}** · ${new Date().toLocaleString('de-DE')}`,
            isSubtle: true,
            size: 'Small'
          }
        ]
      }
    }]
  }
}];
